2221→        // when there are new posts in a followed tag and the user has scrolled the list
2222→        // beyond the first post
2223→        if (event.getResult() == ReaderActions.UpdateResult.HAS_NEW
2224→            && event.getAction() == UpdateAction.REQUEST_NEWER
2225→            && getPostListType() == ReaderPostListType.TAG_FOLLOWED
2226→            && !isPostAdapterEmpty()
2227→            && (!isAdded() || !mRecyclerView.isFirstItemVisible())) {
